#include<stdio.h>
int main()
{
	int n, m;
	scanf("%d %d", &n, &m);
	int i, j;
	int t[102];
	for (i = 0; i < n; i++)
		scanf("%d", &t[i]);
	int t2[102];
	int sum = 0;
	int ans[102];
	int s;
	for (i = 0; i < n; i++)
	{
		if (sum + t[i] <= m)
		{
			ans[i] = 0;
			sum += t[i];
		}
		else
		{
			ans[i] = 0;
			for (j = 0; j < i; j++)
				t2[j] = t[j];
			for (j = 0; j < i - 1; j++)
			{
				if (t2[j] < t2[j + 1])
				{
					t2[j] ^= t2[j + 1];
					t2[j + 1] ^= t2[j];
					t2[j] ^= t2[j + 1];
					if (j > 0)
						j -= 2;
				}
			}
			s = sum;
			j = 0;
			while (s + t[i] > m)
			{
				ans[i]++;
				s -= t2[j];
				j++;
			}
			sum += t[i];
		}
	}
	printf("%d", ans[0]);
	for (i = 1; i < n; i++)
		printf(" %d", ans[i]);
	printf("\n");
	return 0;
}

